parameters.new_string:
/**
 * Send a notification through the appropriate adapter.
 *
 * Notifications are serialized through a delivery queue to guarantee
 * ordering — each notification completes delivery before the next begins.
 * This prevents race conditions where concurrent events (e.g., order:created
 * and order:status-changed) could result in out-of-order delivery.
 */
private sendNotification(params: {
  type: NotificationType;
  userId: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPayload['priority'];
  metadata?: Record<string, string>;
}): Promise<void> {
  this.deliveryQueue = this.deliveryQueue.then(() => this.processNotification(params));
  return this.deliveryQueue;
}

/**
 * Process a single notification delivery.
 *
 * If an adapter is registered for the channel, the notification is
 * delivered through it. If no adapter is registered, the notification
 * is still recorded (with 'sent' status) for backward compatibility
 * and testing without adapters.
 */
private async processNotification(params: {
  type: NotificationType;
  userId: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  priority: NotificationPayload['priority'];
  metadata?: Record<string, string>;
}): Promise<void> {
  // Check user preferences before sending (all channels)
  if (this.preferencesService) {
    if (!this.preferencesService.shouldSend(params.userId, params.type, params.channel)) {
      this.logger.info(`Notification suppressed by preferences: ${params.type} for user ${params.userId} on ${params.channel}`);
      this.historyService?.log({
        notificationId: generateNotificationId(),
        recipient: params.recipient,
        channel: params.channel,
        type: params.type,
        subject: params.subject,
        status: 'suppressed',
        metadata: params.metadata,
      });
      return;
    }
  }

  const notification: Notification = {
    id: generateNotificationId(),
    type: params.type,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    channel: params.channel,
    priority: params.priority,
    status: 'pending',
    createdAt: new Date(),
  };

  const adapter = this.adapters.get(params.channel);
  if (adapter) {
    const payload: NotificationPayload = {
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      channel: params.channel,
      priority: params.priority,
      metadata: params.metadata,
    };

    const result = await adapter.send(payload);
    notification.status = result.success ? 'sent' : 'failed';
    notification.error = result.error;
    notification.sentAt = result.deliveredAt;
  } else {
    // No adapter registered — record notification as sent (useful for testing)
    notification.status = 'sent';
    notification.sentAt = new Date();
  }

  this.notifications.push(notification);
  this.logger.info(`Notification ${notification.status}: ${notification.id} to ${params.recipient}`);

  this.historyService?.log({
    notificationId: notification.id,
    recipient: params.recipient,
    channel: params.channel,
    type: params.type,
    subject: params.subject,
    status: notification.status === 'sent' ? 'sent' : 'failed',
    error: notification.error,
    deliveredAt: notification.sentAt,
    metadata: params.metadata,
  });
}

