  const deliveryLog: string[] = [];
  const slowAdapter: NotificationAdapter = {
    channel: 'email' as const,
    async send(payload: NotificationPayload): Promise<NotificationResult> {
      // First notification takes longer than second to expose ordering bugs
      const delay = payload.subject.includes('Confirmation') ? 50 : 10;
      await new Promise((resolve) => setTimeout(resolve, delay));
      deliveryLog.push(payload.subject);
      return { success: true, channel: 'email', deliveredAt: new Date() };
    },
  };
  service.registerAdapter(slowAdapter);

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  const statusChangedEvent: OrderStatusChangedEvent = {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  };

  // Emit both events concurrently — without the queue fix, the faster
  // status-changed notification would arrive before the slower order confirmation
  const p1 = eventBus.emit(orderCreatedEvent);
  const p2 = eventBus.emit(statusChangedEvent);
  await Promise.all([p1, p2]);

  // Notifications must arrive in emit order, not completion order
  const notifications = service.getNotifications();
  expect(notifications).toHaveLength(2);
  expect(notifications[0]?.type).toBe('order_confirmation');
  expect(notifications[1]?.type).toBe('order_status_update');

  // Adapter delivery log must also be in order
  expect(deliveryLog[0]).toContain('Confirmation');
  expect(deliveryLog[1]).toContain('Update');
});

